__kernel void benchmark_func(T seed, __global T* g_data) {
  const size_t lid = get_local_id(0);
  const size_t gid = get_global_id(0);
  const size_t lsize = get_local_size(0);

#ifdef BLOCK_STRIDED
  const size_t stride = lsize;
  const size_t idx = get_group_id(0) * lsize * (size_t)ELEMENTS_PER_THREAD + lid;
#else
  const size_t stride = get_global_size(0);
  const size_t idx = gid;
#endif

  const size_t big_stride = get_global_size(0) * (size_t)ELEMENTS_PER_THREAD;

  T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; k++) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];
      for (uint i = 0; i < (uint)COMPUTE_ITERATIONS; i++) {
        tmps[j] = mad_custom(tmps[j], tmps[j], seed);
      }
    }

    T sum = conv_int_t(0);
    uint j = 0;
    for (; j + 1 < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_custom(tmps[j], tmps[j + 1], sum);
    }
    if ((ELEMENTS_PER_THREAD & 1) != 0) {
      sum = mad_custom(tmps[ELEMENTS_PER_THREAD - 1], conv_int_t(1), sum);
    }

    if (equal_custom(sum, conv_int_t(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}

